t.t:
.form-page { max-width: 680px; }
.breadcrumb { font-size: 12px; color: var(--text-muted); margin-bottom: 20px; }
.breadcrumb a { color: var(--primary); text-decoration: none; }
.breadcrumb a:hover { text-decoration: underline; }
.context-banner { background: var(--primary-light); border-left: 4px solid var(--primary); border-radius: 0 8px 8px 0; padding: 14px 18px; margin-bottom: 24px; display: flex; align-items: center; gap: 16px; }
.context-banner .cb-title { font-size: 14px; font-weight: 600; color: var(--primary); }
.context-banner .cb-sub { font-size: 12px; color: var(--text-muted); margin-top: 2px; }
.form-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: 12px; padding: 28px; }
.form-card h2 { font-family: 'Source Serif 4', serif; font-size: 20px; color: var(--primary); margin-bottom: 24px; padding-bottom: 16px; border-bottom: 1px solid var(--border); }
.form-section-label { font-size: 10.5px; text-transform: uppercase; letter-spacing: 0.1em; color: var(--text-muted); font-weight: 600; margin-bottom: 14px; margin-top: 24px; }
.form-row { display: flex; gap: 16px; }
.form-group { display: flex; flex-direction: column; gap: 5px; flex: 1; margin-bottom: 14px; }
.form-group label { font-size: 13px; font-weight: 500; color: var(--text-primary); }
.form-group input, .form-group select, .form-group textarea { padding: 9px 12px; border: 1px solid var(--border); border-radius: 6px; font-size: 13.5px; font-family: inherit; color: var(--text-primary); background: var(--bg-card); outline: none; transition: border 0.15s; }
.form-group input:focus, .form-group select:focus, .form-group textarea:focus { border-color: var(--primary); box-shadow: 0 0 0 3px rgba(15,76,129,0.08); }
.form-group textarea { resize: vertical; min-height: 110px; }
.radio-group { display: flex; gap: 10px; flex-wrap: wrap; padding-top: 4px; }
.radio-opt { display: flex; align-items: center; gap: 6px; padding: 6px 14px; border: 1px solid var(--border); border-radius: 20px; cursor: pointer; font-size: 13px; transition: all 0.15s; }
.radio-opt input { accent-color: var(--primary); }
.radio-opt:has(input:checked) { border-color: var(--primary); background: var(--primary-light); color: var(--primary); font-weight: 500; }
.upload-zone { border: 1.5px dashed var(--border); border-radius: 8px; padding: 24px; text-align: center; cursor: pointer; transition: all 0.15s; background: #FAFBFD; }
.upload-zone:hover { border-color: var(--primary); background: var(--primary-light); }
.upload-icon { font-size: 24px; margin-bottom: 8px; }
.upload-text { font-size: 13px; font-weight: 500; color: var(--text-primary); }
.upload-sub { font-size: 11.5px; color: var(--text-muted); margin-top: 3px; }
.checkbox-row { display: flex; align-items: flex-start; gap: 10px; margin-top: 8px; }
.checkbox-row input { margin-top: 3px; accent-color: var(--primary); flex-shrink: 0; }
.checkbox-row label { font-size: 12.5px; color: var(--text-muted); line-height: 1.5; }
.form-actions { display: flex; align-items: center; justify-content: space-between; margin-top: 24px; padding-top: 20px; border-top: 1px solid var(--border); }
.link-back { font-size: 13px; color: var(--primary); text-decoration: none; display: flex; align-items: center; gap: 4px; }
.link-back:hover { text-decoration: underline; }
.success-msg { display: none; background: var(--action-light); border: 1px solid var(--action); border-radius: 10px; padding: 20px 24px; text-align: center; margin-top: 20px; }
.success-msg.show { display: block; }
.success-icon { font-size: 32px; margin-bottom: 8px; }
.success-msg h3 { color: var(--action-dark); font-size: 15px; margin-bottom: 4px; }
.success-msg p { font-size: 13px; color: var(--text-muted); }

t.script:
function updateCounter() {
    document.getElementById('char-count').textContent =
        document.getElementById('motiv-area').value.length + ' / 1000 caracteres';
}

async function submitForm() {
    const btn = event.target;

    const nome  = document.getElementById('f-nome').value.trim();
    const email = document.getElementById('f-email').value.trim();
    const num   = document.getElementById('f-num').value.trim();
    const curso = document.getElementById('f-curso').value;
    const ano   = document.querySelector('input[name="ano"]:checked')?.value;
    const motiv = document.getElementById('motiv-area').value.trim();
    const priv  = document.getElementById('privacy-check').checked;

    // Lê oportunidade_id e tipo dos campos hidden injectados pelo QWeb
    const oppIdRaw = document.getElementById('opp-id').value;
    const oppId    = oppIdRaw ? parseInt(oppIdRaw) : null;
    const tipo     = document.getElementById('opp-tipo').value || 'estagio';

    if (!nome || !email || !num || !curso || !ano) {
        mostrarErro('Preenche todos os campos obrigatórios (*).');
        return;
    }
    if (!priv) {
        mostrarErro('Aceita a política de privacidade para continuar.');
        return;
    }

    btn.disabled = true;
    btn.textContent = 'A enviar...';

    try {
        const response = await fetch('/crm_estudantil/submit_lead', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                jsonrpc: '2.0', method: 'call', id: 1,
                params: {
                    name:             nome,
                    email:            email,
                    phone:            document.getElementById('f-phone').value.trim(),
                    student_number:   num,
                    course:           curso,
                    year:             ano,
                    opportunity_type: tipo,
                    motivation:       motiv,
                    oportunidade_id:  oppId,  // ← liga à oportunidade
                }
            })
        });
        const data = await response.json();
        if (data.result?.success) {
            document.getElementById('form-card').style.display = 'none';
            document.getElementById('success-msg').classList.add('show');
            window.scrollTo({ top: 0, behavior: 'smooth' });
        } else {
            mostrarErro(data.result?.message || 'Erro ao enviar.');
        }
    } catch {
        mostrarErro('Erro de ligação. Verifica se o servidor está online.');
    } finally {
        btn.textContent = 'Enviar Candidatura';
        btn.disabled = false;
    }
}

function mostrarErro(msg) {
    const el = document.getElementById('form-error');
    el.textContent = '⚠ ' + msg;
    el.style.display = 'block';
}
